import { useState, useEffect } from "react";
import { useParams } from "react-router-dom";
import { useNavigate } from "react-router-dom";
import { createOrder } from "../services/orderService";
import {
  Card,
  Button,
  Form,
  Row,
  Col,
  Spinner,
  Alert,
  Container,
  Badge,
} from "react-bootstrap";
import { getEventById } from "../services/eventService";

function EventDetailPage() {
  const { eventId } = useParams();

  const [event, setEvent] = useState(null);
  const [ticketTypes, setTicketTypes] = useState([]);
  const [selectedTicket, setSelectedTicket] = useState(null);
  const [quantity, setQuantity] = useState(1);
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchEventDetails = async () => {
      try {
        setLoading(true);
        setError("");

        if (!eventId) {
          setError("ID sự kiện không hợp lệ.");
          return;
        }

        const response = await getEventById(eventId);

        if (response.data?.success && response.data?.data) {
          setEvent(response.data.data);
          setTicketTypes(response.data.data.ticket_types || []);
        } else {
          setError("Không có thông tin sự kiện.");
        }
      } catch (err) {
        console.error("Error fetching event details:", err);
        setError("Lỗi khi tải chi tiết sự kiện.");
      } finally {
        setLoading(false);
      }
    };

    fetchEventDetails();
  }, [eventId]);

  const handleTicketSelection = (ticketId) => {
    setSelectedTicket(ticketId);
    setQuantity(1);
  };

  const handleQuantityChange = (e, maxPerOrder, quantityAvailable) => {
    const value = Number(e.target.value);
    const maxAllowed = Math.min(maxPerOrder || 1, quantityAvailable || 1);

    if (value < 1) {
      setQuantity(1);
      return;
    }

    if (value > maxAllowed) {
      setQuantity(maxAllowed);
      return;
    }

    setQuantity(value);
  };

  const handleAddToCart = () => {
    if (!selectedTicket) {
      alert("Vui lòng chọn loại vé.");
      return;
    }

    const selectedTicketData = ticketTypes.find(
      (ticket) => ticket.id === selectedTicket
    );

    console.log("Loại vé đã chọn:", selectedTicketData);
    console.log("Số lượng:", quantity);

    alert(
      `Đã chọn ${quantity} vé ${
        selectedTicketData?.name || ""
      }. Bước tiếp theo sẽ nối sang tạo order.`
    );
  };

  const renderStatusBadge = (status) => {
    switch (status) {
      case "on_sale":
        return <Badge bg="success">Đang mở bán</Badge>;
      case "upcoming":
        return <Badge bg="warning" text="dark">Sắp diễn ra</Badge>;
      case "sold_out":
        return <Badge bg="secondary">Hết vé</Badge>;
      case "ended":
        return <Badge bg="dark">Đã kết thúc</Badge>;
      default:
        return <Badge bg="info">{status}</Badge>;
    }
  };

  if (loading) {
    return (
      <div
        className="d-flex justify-content-center align-items-center"
        style={{ minHeight: "100vh" }}
      >
        <Spinner animation="border" variant="primary" />
      </div>
    );
  }

  if (error) {
    return (
      <Container className="my-5">
        <Alert variant="danger">{error}</Alert>
      </Container>
    );
  }

  if (!event) {
    return (
      <Container className="my-5">
        <Alert variant="warning">Không tìm thấy sự kiện.</Alert>
      </Container>
    );
  }

  return (
    <Container className="my-5">
      <Row className="g-4 mb-5">
        <Col md={6}>
          <img
            src={
              event.banner_image
                ? `/images/${event.banner_image}`
                : "/images/default-banner.jpg"
            }
            alt={event.title}
            style={{
              width: "100%",
              height: "100%",
              maxHeight: "420px",
              objectFit: "cover",
              borderRadius: "12px",
            }}
            onError={(e) => {
              e.target.src = "/images/default-banner.jpg";
            }}
          />
        </Col>

        <Col md={6}>
          <div className="d-flex align-items-center gap-2 mb-3">
            <h2 className="mb-0">{event.title}</h2>
            {renderStatusBadge(event.status)}
          </div>

          <p>
            <strong>Mô tả:</strong> {event.description || "Không có mô tả"}
          </p>

          <p>
            <strong>Địa điểm:</strong> {event.location || "Chưa cập nhật"}
          </p>

          <p>
            <strong>Ngày tổ chức:</strong>{" "}
            {event.event_date
              ? new Date(event.event_date).toLocaleString("vi-VN")
              : "Chưa cập nhật"}
          </p>

          <p>
            <strong>Ban tổ chức:</strong>{" "}
            {event.organizer_name || "Chưa cập nhật"}
          </p>

          <p>
            <strong>Slug:</strong> {event.slug || "Không có"}
          </p>
        </Col>
      </Row>

      <Row className="mb-3">
        <Col>
          <h4>Chọn loại vé</h4>
        </Col>
      </Row>

      {ticketTypes.length === 0 ? (
        <Alert variant="warning">Sự kiện này hiện chưa có loại vé nào.</Alert>
      ) : (
        <>
          <Row>
            {ticketTypes.map((ticket) => {
              const quantityAvailable =
                ticket.quantity_available ??
                ticket.quantity_total - ticket.quantity_sold;

              const maxAllowed = Math.min(
                ticket.max_per_order || 1,
                quantityAvailable || 1
              );

              return (
                <Col key={ticket.id} md={6} lg={4}>
                  <Card className="mb-4 h-100 shadow-sm">
                    <Card.Body>
                      <Card.Title>{ticket.name}</Card.Title>

                      <Card.Text>
                        {ticket.description || "Không có mô tả"}
                      </Card.Text>

                      <Card.Text>
                        <strong>Giá:</strong>{" "}
                        {Number(ticket.price).toLocaleString("vi-VN")} VNĐ
                      </Card.Text>

                      <Card.Text>
                        <strong>Còn lại:</strong> {quantityAvailable}
                      </Card.Text>

                      <Card.Text>
                        <strong>Tối đa / đơn:</strong> {ticket.max_per_order}
                      </Card.Text>

                      <Card.Text>
                        <strong>Trạng thái:</strong>{" "}
                        {ticket.status === "active" ? "Đang bán" : ticket.status}
                      </Card.Text>

                      <Form.Check
                        type="radio"
                        name="ticket"
                        label={`Chọn ${ticket.name}`}
                        checked={selectedTicket === ticket.id}
                        onChange={() => handleTicketSelection(ticket.id)}
                      />

                      {selectedTicket === ticket.id && (
                        <Form.Group className="mt-3">
                          <Form.Label>Số lượng</Form.Label>
                          <Form.Control
                            type="number"
                            min={1}
                            max={maxAllowed}
                            value={quantity}
                            onChange={(e) =>
                              handleQuantityChange(
                                e,
                                ticket.max_per_order,
                                quantityAvailable
                              )
                            }
                          />
                          <Form.Text className="text-muted">
                            Bạn có thể chọn tối đa {maxAllowed} vé.
                          </Form.Text>
                        </Form.Group>
                      )}
                    </Card.Body>
                  </Card>
                </Col>
              );
            })}
          </Row>

          <Button variant="primary" onClick={handleAddToCart}>
            Thêm vào giỏ
          </Button>
        </>
      )}
    </Container>
  );
}

export default EventDetailPage;
